488	QEMU_PLUGIN_EXPORT int qemu_plugin_install(qemu_plugin_id_t id,
489	                                           const qemu_info_t *info,
490	                                           int argc, char **argv)
491	{
492	    (void) info;
493	    for (int i = 0; i < argc; i++) {
494	        g_auto(GStrv) tok = g_strsplit(argv[i], "=", 2);
495	        if (g_strcmp0(tok[0], "outfile") == 0 && tok[1]) {
496	            outfile_path = g_strdup(tok[1]);
497	        } else if (g_strcmp0(tok[0], "enter_pc") == 0 && tok[1]) {
498	            char *endp = NULL;
499	            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
500	            if (!endp || *endp != '\0') {
501	                fprintf(stderr, "hybrid_handoff: invalid enter_pc=%s\n",
502	                        tok[1]);
503	                return -1;
504	            }
505	            enter_pc_arg = (uint64_t) v;
506	            pc_mode = 1;
507	        } else if (g_strcmp0(tok[0], "icount") == 0 && tok[1]) {
508	            char *endp = NULL;
509	            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
510	            if (!endp || *endp != '\0' || v == 0) {
511	                fprintf(stderr, "hybrid_handoff: invalid icount=%s\n",
512	                        tok[1]);
513	                return -1;
514	            }
515	            icount_target = (uint64_t) v;
516	            icount_mode = 1;
517	        } else if (g_strcmp0(tok[0], "bbv_out") == 0 && tok[1]) {
518	            bbv_out_path = g_strdup(tok[1]);
519	            bbv_mode = 1;
520	        } else if (g_strcmp0(tok[0], "slice") == 0 && tok[1]) {
521	            char *endp = NULL;
522	            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
523	            if (!endp || *endp != '\0' || v == 0) {
524	                fprintf(stderr, "hybrid_handoff: invalid slice=%s\n",
525	                        tok[1]);
526	                return -1;
527	            }
528	            bbv_slice_target = (uint64_t) v;
529	        } else if (g_strcmp0(tok[0], "slice_at") == 0 && tok[1]) {
530	            char *endp = NULL;
531	            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
532	            if (!endp || *endp != '\0') {
533	                fprintf(stderr, "hybrid_handoff: invalid slice_at=%s\n",
534	                        tok[1]);
535	                return -1;
536	            }
537	            slice_at_target = (uint64_t) v;
538	            slice_consume_mode = 1;
539	        } else if (g_strcmp0(tok[0], "drain_at_exit") == 0 && tok[1]) {
540	            // F14: any non-zero value enables. "1" is the canonical form
541	            // hsim emits; other ints (incl. negatives parsed as huge unsigned)
542	            // also enable -- the flag is a binary switch, not a count.
543	            char *endp = NULL;
544	            unsigned long long v = g_ascii_strtoull(tok[1], &endp, 0);
545	            if (!endp || *endp != '\0') {
546	                fprintf(stderr, "hybrid_handoff: invalid drain_at_exit=%s\n",
547	                        tok[1]);
548	                return -1;
549	            }
550	            drain_at_exit_mode = (v != 0);
551	        } else {
552	            fprintf(stderr, "hybrid_handoff: unknown option: %s\n", argv[i]);
553	            return -1;
554	        }
555	    }
556	    if (!outfile_path) {
557	        fputs("hybrid_handoff: outfile=PATH is required\n", stderr);
558	        return -1;
559	    }
560	    if (pc_mode) {
561	        fprintf(stderr,
562	                "hybrid_handoff: PC-mode enter=0x%" PRIx64 "\n",
563	                enter_pc_arg);
564	    }
565	    if (icount_mode) {
566	        fprintf(stderr,
567	                "hybrid_handoff: icount-mode target=%" PRIu64 "\n",
568	                icount_target);
569	    }
570	    if (bbv_mode) {
571	        if (bbv_slice_target == 0) {
572	            fputs("hybrid_handoff: bbv_out= requires slice=N\n", stderr);
573	            return -1;
574	        }
575	        bbv_emit = bbv_emit_new(bbv_out_path, bbv_slice_target);
576	        if (!bbv_emit) {
577	            fprintf(stderr, "hybrid_handoff: failed to open bbv_out=%s\n",
578	                    bbv_out_path);
579	            return -1;
580	        }
581	        fprintf(stderr,
582	                "hybrid_handoff: bbv-mode out=%s slice=%" PRIu64 "\n",
583	                bbv_out_path, bbv_slice_target);
584	    }
585	    if (slice_consume_mode) {
586	        if (bbv_slice_target == 0) {
587	            fputs("hybrid_handoff: slice_at= requires slice=N\n", stderr);
588	            return -1;
589	        }
590	        fprintf(stderr,
591	                "hybrid_handoff: slice-consume mode slice=%" PRIu64
592	                " slice_at=%" PRIu64 "\n",
593	                bbv_slice_target, slice_at_target);
594	    }
595	    if (drain_at_exit_mode) {
596	        fputs("hybrid_handoff: drain-at-exit mode enabled\n", stderr);
597	        qemu_plugin_register_atexit_cb(id, on_atexit, NULL);
598	    }
599	
600	    vcpu_state = qemu_plugin_scoreboard_new(sizeof(VcpuRegs));
601	    qemu_plugin_register_vcpu_tb_trans_cb(id, vcpu_tb_trans);
602	    return 0;
603	}
